from langchain_community.embeddings import OllamaEmbeddings

# Create an Ollama embedding model
embeddings = OllamaEmbeddings(
    model="nomic-embed-text"
)

# List of texts to convert into embedding vectors
texts = [
    "Alpha is the first letter of Greek alphabet",
    "Beta is the second letter of Greek alphabet",
]

# Generate embedding vectors for all texts
result = embeddings.embed_documents(texts)

# Print all embedding vectors
print(result)

# Print the number of embedding vectors
print("Number of embeddings:", len(result))

# Print the embedding dimensions
print("Embedding dimensions:", len(result[0]))


